# ── Global dark theme styling ──────────────────────────────────────────────────
st.markdown("""
<style>
@import url('https://fonts.googleapis.com/css2?family=Barlow+Condensed:wght@300;400;600;700;800&family=Barlow:wght@300;400;500;600&display=swap');

html, body, [class*="css"] { font-family: 'Barlow', sans-serif; background-color: #0d0d0d; color: #e8e8e8; }
.stApp { background-color: #0d0d0d; }
[data-testid="stSidebar"] { background-color: #111111; border-right: 1px solid #1e1e1e; }
[data-testid="stSidebar"] * { color: #cccccc !important; }

.f1-header {
    background: linear-gradient(135deg, #e10600 0%, #a00400 50%, #1a0000 100%);
    padding: 2rem 2.5rem 1.5rem; border-radius: 4px; margin-bottom: 1.5rem;
    position: relative; overflow: hidden;
}
.f1-header::before {
    content: "F1"; position: absolute; right: -10px; top: -20px;
    font-family: 'Barlow Condensed', sans-serif; font-size: 10rem; font-weight: 800;
    color: rgba(255,255,255,0.04); line-height: 1;
}
.f1-header h1 {
    font-family: 'Barlow Condensed', sans-serif; font-size: 3rem; font-weight: 800;
    letter-spacing: 0.04em; text-transform: uppercase; color: #ffffff; margin: 0; line-height: 1;
}
.f1-header p { color: rgba(255,255,255,0.65); font-size: 0.95rem; margin: 0.5rem 0 0;
    font-weight: 300; letter-spacing: 0.08em; text-transform: uppercase; }

.section-label {
    font-family: 'Barlow Condensed', sans-serif; font-size: 1.4rem; font-weight: 700;
    letter-spacing: 0.1em; text-transform: uppercase; color: #e10600;
    border-left: 3px solid #e10600; padding-left: 0.75rem; margin: 2rem 0 1rem;
}
.kpi-grid { display: flex; gap: 1rem; margin-bottom: 1.5rem; flex-wrap: wrap; }
.kpi-card {
    flex: 1; min-width: 130px; background: #161616; border: 1px solid #222;
    border-top: 3px solid #e10600; border-radius: 4px; padding: 1rem 1.2rem;
}
.kpi-value { font-family: 'Barlow Condensed', sans-serif; font-size: 2.2rem; font-weight: 800; color: #ffffff; line-height: 1; }
.kpi-label { font-size: 0.72rem; font-weight: 500; letter-spacing: 0.12em; text-transform: uppercase; color: #888; margin-top: 0.3rem; }

[data-baseweb="tab-list"] { background: #111; border-bottom: 1px solid #222; }
[data-baseweb="tab"] { color: #888 !important; font-family: 'Barlow Condensed', sans-serif;
    font-size: 1rem; letter-spacing: 0.08em; text-transform: uppercase; }
[data-baseweb="tab"][aria-selected="true"] { color: #e10600 !important; border-bottom-color: #e10600 !important; }

[data-testid="stMetric"] { background: #161616; border: 1px solid #222; padding: 1rem; border-radius: 4px; }
[data-testid="stMetricLabel"] { color: #888 !important; font-size: 0.75rem !important; text-transform: uppercase; letter-spacing: 0.08em; }
[data-testid="stMetricValue"] { font-family: 'Barlow Condensed', sans-serif; font-size: 2rem !important; color: #fff !important; }

[data-testid="stDownloadButton"] button {
    background: #e10600 !important; color: white !important; border: none !important;
    font-family: 'Barlow Condensed', sans-serif !important; font-size: 1rem !important;
    letter-spacing: 0.08em !important; text-transform: uppercase !important; font-weight: 700 !important;
}
</style>
""", unsafe_allow_html=True)

# ── Matplotlib dark theme ──────────────────────────────────────────────────────
plt.rcParams.update({
    "figure.facecolor": "#111111", "axes.facecolor": "#111111",
    "axes.edgecolor": "#2a2a2a", "axes.labelcolor": "#aaaaaa",
    "axes.titlecolor": "#dddddd", "xtick.color": "#666666", "ytick.color": "#666666",
    "grid.color": "#1e1e1e", "grid.linewidth": 0.8, "text.color": "#cccccc",
    "font.family": "sans-serif", "axes.spines.top": False, "axes.spines.right": False,
})

F1_RED = "#e10600"
F1_GOLD = "#FFD700"

# ── Load embedded data ─────────────────────────────────────────────────────────
@st.cache_data
def load_data():
    records = json.loads(_RAW_JSON)
    df = pd.DataFrame(records)
    df["Date"] = pd.to_datetime(df["Date"])
    df["Position"] = pd.to_numeric(df["Position"], errors="coerce")
    df["GridPosition"] = pd.to_numeric(df["GridPosition"], errors="coerce")
    df["Points"] = pd.to_numeric(df["Points"], errors="coerce").fillna(0)
    df["Laps"] = pd.to_numeric(df["Laps"], errors="coerce").fillna(0).astype(int)
    df["Win"] = pd.to_numeric(df["Win"], errors="coerce").fillna(0).astype(int)
    df["Podium"] = pd.to_numeric(df["Podium"], errors="coerce").fillna(0).astype(int)
    df["PointsFinish"] = pd.to_numeric(df["PointsFinish"], errors="coerce").fillna(0).astype(int)
    df["FastestLap"] = pd.to_numeric(df["FastestLap"], errors="coerce").fillna(0).astype(int)
    return df

df = load_data()

TEAM_COLORS = df.drop_duplicates("TeamName").set_index("TeamName")["TeamColor"].to_dict()
DRIVER_TEAMS = df.drop_duplicates("FullName").set_index("FullName")["TeamName"].to_dict()

def team_color(team): return TEAM_COLORS.get(team, "#888888")
def driver_color(driver): return team_color(DRIVER_TEAMS.get(driver, ""))

# ── Sidebar ────────────────────────────────────────────────────────────────────
with st.sidebar:
    st.markdown("### 🏎️ F1 2025 ANALYSIS")
    st.markdown("---")
    all_drivers = sorted(df["FullName"].unique())
    all_teams   = sorted(df["TeamName"].unique())

    selected_drivers = st.multiselect("FILTER DRIVERS", all_drivers, default=all_drivers[:6])
    if not selected_drivers: selected_drivers = all_drivers

    selected_teams = st.multiselect("FILTER TEAMS", all_teams, default=all_teams)
    if not selected_teams: selected_teams = all_teams

    round_range = st.slider("RACE ROUNDS", 1, int(df["Round"].max()), (1, int(df["Round"].max())))

    st.markdown("---")
    st.markdown("**DATASET STATS**")
    st.markdown(f"📋 **Records:** {len(df):,}")
    st.markdown(f"🏁 **Races:** {df['Venue'].nunique()}")
    st.markdown(f"👤 **Drivers:** {df['FullName'].nunique()}")
    st.markdown(f"🏎️ **Teams:** {df['TeamName'].nunique()}")
    st.markdown("---")
    st.markdown("*Built with FastF1 + Streamlit*")

