    with col1:
        st.markdown('<div class="section-label">Correlation Heatmap</div>', unsafe_allow_html=True)
        corr_cols = ["Position", "Points", "Laps", "Win", "Podium", "PointsFinish", "FastestLap", "GridPosition"]
